import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { PolymarketService } from '@/lib/services/polymarket.service';
import { KalshiService } from '@/lib/services/kalshi.service';

export const dynamic = 'force-dynamic';
export const maxDuration = 120;

const CRON_SECRET = process.env.CRON_SECRET;

// Prefijos de tickers de Kalshi que son parlays/combos — no tienen equivalente en Polymarket
const KALSHI_PARLAY_PREFIXES = ['KXMVE', 'KXMULTI', 'KXCOMBO', 'KXPARLAY'];

function isParlay(ticker: string): boolean {
  return KALSHI_PARLAY_PREFIXES.some(prefix => ticker.startsWith(prefix));
}

function isAuthorized(req: NextRequest): boolean {
  if (process.env.NODE_ENV === 'development') return true;
  const auth = req.headers.get('authorization');
  return auth === `Bearer ${CRON_SECRET}`;
}

export async function GET(req: NextRequest) {
  if (!isAuthorized(req)) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const startTime = Date.now();
  const results = {
    kalshi: { fetched: 0, skippedParlays: 0, newInDB: 0 },
    polymarket: { fetched: 0, newInDB: 0 },
    durationMs: 0
  };

  // ── KALSHI: hasta 5 páginas (1,000 markets) ──────────────────────────
  try {
    const kalshiService = new KalshiService();
    let cursor: string | undefined;
    const MAX_KALSHI_PAGES = 5;

    for (let page = 0; page < MAX_KALSHI_PAGES; page++) {
      const response = await kalshiService.getMarkets({
        status: 'open',
        limit: 200,
        cursor
      });

      const markets = response.markets ?? [];
      if (markets.length === 0) break;

      // Filtrar parlays
      const validMarkets = markets.filter(m => !isParlay(m.ticker));
      results.kalshi.fetched += validMarkets.length;
      results.kalshi.skippedParlays += markets.length - validMarkets.length;

      if (validMarkets.length > 0) {
        // Verificar cuáles ya existen en DB
        const tickers = validMarkets.map(m => m.ticker);
        const existing = await prisma.market.findMany({
          where: { platform: 'KALSHI', externalId: { in: tickers } },
          select: { externalId: true }
        });
        const existingSet = new Set(existing.map(m => m.externalId));
        const newMarkets = validMarkets.filter(m => !existingSet.has(m.ticker));

        if (newMarkets.length > 0) {
          const normalized = newMarkets.map(m => kalshiService.normalizeMarket(m));
          await prisma.market.createMany({
            data: normalized,
            skipDuplicates: true
          });
          results.kalshi.newInDB += newMarkets.length;
          console.log(`[discover] Kalshi page ${page + 1}: ${newMarkets.length} new markets inserted`);
        }
      }

      cursor = response.cursor;
      if (!cursor) break;

      await new Promise(r => setTimeout(r, 150));
    }
  } catch (err) {
    console.error('[discover] Kalshi error:', err);
  }

  // ── POLYMARKET: últimos 100 eventos ──────────────────────────────────
  try {
    const polyService = new PolymarketService();

    const response = await fetch(
      'https://gamma-api.polymarket.com/events?active=true&closed=false&limit=100&offset=0',
      { headers: { Accept: 'application/json' }, cache: 'no-store' }
    );

    if (!response.ok) {
      console.error(`[discover] Polymarket API error: ${response.status}`);
    } else {
      const events = await response.json() as Array<{
        id: string;
        slug?: string;
        title?: string;
        markets?: Array<Record<string, unknown>>;
      }>;

      const allMarkets: Array<{
        raw: Record<string, unknown>;
        eventInfo: { id: string; slug?: string; title?: string }
      }> = [];

      for (const event of events ?? []) {
        const eventInfo = { id: event.id, slug: event.slug, title: event.title };
        const markets = event.markets && event.markets.length > 0
          ? event.markets
          : [event as unknown as Record<string, unknown>];

        for (const m of markets) {
          const raw = typeof m === 'object' && m && 'id' in m
            ? m as Record<string, unknown>
            : { id: event.id, ...m };
          allMarkets.push({ raw, eventInfo });
        }
      }

      results.polymarket.fetched = allMarkets.length;

      if (allMarkets.length > 0) {
        // Verificar cuáles ya existen en batch
        const externalIds = allMarkets.map(({ raw }) =>
          String(raw.id ?? raw.conditionId ?? raw.slug ?? '')
        ).filter(Boolean);

        const existing = await prisma.market.findMany({
          where: { platform: 'POLYMARKET', externalId: { in: externalIds } },
          select: { externalId: true }
        });
        const existingSet = new Set(existing.map(m => m.externalId));

        const newMarkets = allMarkets.filter(({ raw }) => {
          const externalId = String(raw.id ?? raw.conditionId ?? raw.slug ?? '');
          return externalId && !existingSet.has(externalId);
        });

        if (newMarkets.length > 0) {
          const normalized = newMarkets.map(({ raw, eventInfo }) =>
            polyService.normalizeMarket(raw, eventInfo)
          );
          await prisma.market.createMany({
            data: normalized,
            skipDuplicates: true
          });
          results.polymarket.newInDB += newMarkets.length;
          console.log(`[discover] Polymarket: ${newMarkets.length} new markets inserted`);
        }
      }
    }
  } catch (err) {
    console.error('[discover] Polymarket error:', err);
  }

  results.durationMs = Date.now() - startTime;

  console.log(`[discover-markets] Done in ${results.durationMs}ms`, results);

  await prisma.syncLog.create({
    data: {
      platform: 'KALSHI',
      lastSyncedAt: new Date(),
      marketsCount: results.kalshi.newInDB,
      duration: Math.round(results.durationMs / 1000),
      errors: 0
    }
  });

  return NextResponse.json(results);
}